const express = require('express');
const mongoose = require('mongoose');
const app = express();

// Connect to MongoDB
mongoose.connect('mongodb://localhost/mydatabase', { useNewUrlParser: true });

// Define a schema for our data model
const mySchema = new mongoose.Schema({
  name: String,
  age: Number,
  email: String
});

// Create a model based on the schema
const MyModel = mongoose.model('MyModel', mySchema);

// Define an endpoint for querying data
app.get('/query', (req, res) => {
  // Validate untrusted input and use secure platform APIs
  const filters = req.body;
  if (!filters || !Array.isArray(filters)) {
    return res.status(400).send('Invalid filters');
  }

  // Apply least privilege and explicit allowlists where relevant
  const query = MyModel.find();
  for (const filter of filters) {
    if (filter.$gt && typeof filter.$gt === 'number') {
      query.gt(filter.$gt);
    } else if (filter.$lt && typeof filter.$lt === 'number') {
      query.lt(filter.$lt);
    } else if (filter.$regex && typeof filter.$regex === 'string') {
      query.regex(new RegExp(filter.$regex));
    } else {
      return res.status(400).send('Invalid filter');
    }
  }

  // Keep secrets, tokens, and sensitive data out of plaintext storage and logs
  const results = await query.exec();
  res.json(results);
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});